import 'package:equatable/equatable.dart'; enum SessionType { screenShare, remoteControl, fileTransfer, voiceCall } enum SessionStatus { idle, connecting, active, paused, ended } class SessionEntity extends Equatable { final String sessionId; final String hostId; final String viewerId; final SessionType type; final SessionStatus status; final DateTime startedAt; const SessionEntity({required this.sessionId, required this.hostId, required this.viewerId, required this.type, this.status = SessionStatus.idle, required this.startedAt}); @override List<Object?> get props => [sessionId, status]; bool get isActive => status == SessionStatus.active; Duration get duration => DateTime.now().difference(startedAt); }
